INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0603308A$$, 2026, $$This Program Element (PE) funds the United States Army Space and Missile Defense Command (USASMDC) development activities, and employment of global space
and high-altitude (SHA) capabilities to the Army, joint force, allies and partners, to enable multi-domain combat effects; enhance deterrence, assurance, and detection
of strategic attacks; and protect the Nation. The USASMDC is the warfighting function lead and Department of the Army force modernization proponent for integration
of current and future SHA systems to enable Army forces on the battlefield. The USASMDC workforce supports the research and doctrine development from one of the
USASMDC principal locations in Huntsville, AL; Colorado Springs, CO; and Joint Base Langley-Eustis. Employing cutting-edge technology and incorporating feedback
from the warfighter, the command develops critical space and high-altitude capabilities to maintain overmatch of the nation's near-peer adversaries and to deter, deny
and defeat any challenge. Headquarters, Department of the Army General Order 37, dated 16 October 2006, designated USASMDC as the Army proponent for space,
the Army integrator for global missile defense (GMD), and the Army Service Component Command (ASCC) of the USSTRATCOM. Army Regulation (AR) 10-87, Army
Commands, Army Service Component Commands, and Direct Reporting Units, dated 4 September 2007, and AR 5-22, The Army Force Modernization Proponent
System, dated 19 August 2009, designated USASMDCas the Army specified proponent for Space/High Altitude capabilities. As the Army proponent for space and
high altitude, USASMDC is responsible for developing warfighting concepts, conduct warfighting experiments to validate those concepts, identify capabilities needed
to implement the validated concepts, and develop Doctrine, Organizations, Training, Material, Leadership & Education, Personnel, Facilities and Policy (DOTMLPF-P)
solutions.

 The FY 2026 request was reduced by $2.577 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in
 alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative."

 The FY 2026 request was reduced by $0.406 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the
 President's Department of Government Efficiency Workforce Optimization Initiative."
Component Development & Prototypes (ACD&P)$$, $$This Program Element (PE) funds the Space and High Altitude (SHA) Force Development activities of the United States Army Space and Missile Defense Command
(USASMDC) Space and Missile Defense Center of Excellence (SMDCoE) and Technical Center (TC). The SMDCoE is the warfighting function lead and Department of
the Army force modernization proponent for integration of current and future SHA systems to enable Army forces on the battlefield. The SMDCoE workforce supports
the research and doctrine development from one of the SMDCoE principle locations in Huntsville, AL; Colorado Springs, CO; and Joint Base Langley-Eustis. As
the Army proponent for SHA, the SMDCoE is responsible for developing warfighting concepts, identifying and validating needed capabilities, conducting warfighting
experiments, and developing Doctrine, Organizations, Training, Material, Leadership & Education, Personnel, Facilities and Policy (DOTMLPF-P) solutions for the Army
to leverage the SHA domains in support of Army operations. The SMDCoE focuses on providing solutions for capability gaps of land domain forces in a multi-domain
battle environment in two ways: First, by leveraging the benefits of the SHA domains to enable decentralized land force operations in support of the Army's mission
command philosophy; and second by delivering synchronized capabilities from, through and into the space domain in direct support of land domain forces. Effective
integration of SHA capabilities enable the application of strategic land power and execution of Multi-Domain Operations (MDO). Additionally, SHA capabilities anchor
the Army's ability to penetrate and disintegrate enemy anti-access and area denial (A2AD) systems and exploit the resultant freedom of maneuver to achieve strategic
objectives and force a return to competition on favorable terms. Under the direction of an experienced member of the Senior Executive Service (SES), the SMDCoE
receives guidance from the USASMDC Commanding General and works in close coordination with the Army Combined Arms Center, Army Futures Command, the
United States Strategic Command, the United States Space Command the Missile Defense Agency.

